int n, m, i, j, k, u, v, ans, a[N], b[N], c[N], d[N], e[N], f[N], g[N], h[N], i[N], j[N], k[N], l[N], m[N], n[N], o[N], p[N], q[N], r[N], s[N], t[N], u[N], v[N], w[N], x[N], y[N], z[N];

int dfs(int x, int y) {
    int i, j, k, l, m, n, o, p, q, r, s, t, u, v, w, x, y, z;
    if (y == 0) return 0;
    for (i = 0; i < n; i++) {
        if (a[i] == x) {
            a[i] = 0;
            return 1 + dfs(i, y - 1);
        }
    }
